98	/// A `qkernel` must be used to wrap `CUDA-Q` kernels (callables annotated
99	/// with the `__qpu__` attribute) when those kernels are \e referenced other
100	/// than by a direct call in code outside of quantum kernels proper. Supports
101	/// free functions, classes with call operators, and lambdas.
102	///
103	/// The quake compiler can inspect these wrappers in the C++ code and tweak them
104	/// to provide information necessary and sufficient for the CUDA-Q runtime to
105	/// either stitch together execution in a simulation environment and/or JIT
106	/// compile and re-link these kernels into a cohesive quantum circuit.
107	template <typename>
108	class qkernel;
109	
110	template <typename R, typename... As>
111	class qkernel<R(As...)> {
112	public:
113	  using function_type = R(As...);
114	
115	  qkernel() {}
116	  qkernel(std::nullptr_t) {}
117	  qkernel(const qkernel &) = default;
118	  qkernel(qkernel &&) = default;
119	
120	  template <typename FUNC,
121	            bool SELF = std::is_same_v<remove_cvref_t<FUNC>, qkernel>>
122	  using DecayType = typename std::enable_if_t<!SELF, std::decay<FUNC>>::type;
123	
124	  template <typename FUNC, typename DFUNC = DecayType<FUNC>,
125	            typename RES =
126	                std::conditional_t<std::is_invocable_r_v<R, DFUNC, As...>,
127	                                   std::true_type, std::false_type>>
128	  struct CallableType : RES {};
129	
130	  template <typename S, typename = std::enable_if_t<CallableType<S>::value>>
131	  qkernel(S &&f) {
132	    using PS = remove_cvref_t<S>;
133	    if constexpr (std::is_same_v<PS, R (*)(As...)> ||
134	                  std::is_same_v<PS, R(As...)>) {
135	      kernelCallable =
136	          std::make_unique<detail::QKernelHolder<R, R (*)(As...), As...>>(f);
137	    } else {
138	      kernelCallable = std::make_unique<detail::QKernelHolder<R, PS, As...>>(f);
139	    }
140	  }
141	
142	  R operator()(As... as) const {
143	    return kernelCallable->dispatch(std::forward<As>(as)...);
144	  }
145	  R operator()(As... as) {
146	    return kernelCallable->dispatch(std::forward<As>(as)...);
147	  }
148	
149	  void **get_entry_kernel_from_holder() const {
150	    return static_cast<void **>(kernelCallable->getEntry());
151	  }
152	
153	private:
154	  std::unique_ptr<detail::QKernelInterface<R, As...>> kernelCallable;
155	};
