30	// This file describes the API for a default qubit logical instruction
31	// set for CUDA-Q kernels.
32	
33	namespace cudaq {
34	
35	namespace detail {
36	void warn(const std::string_view msg);
37	}
38	
39	// Define the common single qubit operations.
40	namespace qubit_op {
41	#define ConcreteQubitOp(NAME)                                                  \
42	  struct NAME##Op {                                                            \
43	    static const std::string name() { return #NAME; }                          \
44	  };
45	
46	ConcreteQubitOp(h) ConcreteQubitOp(x) ConcreteQubitOp(y) ConcreteQubitOp(z)
47	    ConcreteQubitOp(s) ConcreteQubitOp(t) ConcreteQubitOp(rx)
48	        ConcreteQubitOp(ry) ConcreteQubitOp(rz) ConcreteQubitOp(r1)
49	            ConcreteQubitOp(u3)
50	
51	} // namespace qubit_op
52	
53	// Convert a qubit to its unique id representation
54	inline QuditInfo qubitToQuditInfo(qubit &q) { return {q.n_levels(), q.id()}; }
55	inline bool qubitIsNegative(qubit &q) { return q.is_negative(); }
56	
57	/// C++20 variant using templates.
58	
59	/// This function will apply the specified `QuantumOp`. It will check the
60	/// modifier template type and if it is `base`, it will apply the operation to
61	/// any qubits provided as input. If `ctrl`, it will take the first `N-1` qubits
62	/// as the controls and the last qubit as the target.
63	template <typename QuantumOp, typename mod = base, typename... QubitArgs>
64	void oneQubitApply(QubitArgs &...args) {
65	  // Get the name of this operation
66	  auto gateName = QuantumOp::name();
67	  static_assert(std::conjunction<std::is_same<qubit, QubitArgs>...>::value,
68	                "Cannot operate on a qudit with Levels != 2");
69	
70	  // Get the number of input qubits
71	  constexpr std::size_t nArgs = sizeof...(QubitArgs);
72	
73	  // Map the qubits to their unique ids and pack them.
74	  std::vector<QuditInfo> quditInfos{qubitToQuditInfo(args)...};
75	  std::vector<bool> qubitIsNegated{qubitIsNegative(args)...};
76	
77	  // If mod == base, then we just want to apply the gate to all qubits provided.
78	  // This is a broadcast application.
79	  if constexpr (std::is_same_v<mod, base>) {
80	    for (auto &qubit : quditInfos)
81	      getExecutionManager()->apply(gateName, {}, {}, {qubit});
82	
83	    // Nothing left to do, return
84	    return;
85	  }
86	
87	  // If we are here, then `mod` must be control or adjoint. Extract the controls
88	  // and the target
89	  std::vector<QuditInfo> controls(quditInfos.begin(),
90	                                  quditInfos.begin() + nArgs - 1);
91	
92	  // If we have controls, check if any of them are negative controls, and if so
93	  // apply an x.
94	  if (!controls.empty())
95	    for (std::size_t i = 0; i < controls.size(); i++)
96	      if (qubitIsNegated[i])
97	        getExecutionManager()->apply("x", {}, {}, {controls[i]});
98	
99	  // Apply the gate
100	  getExecutionManager()->apply(gateName, {}, controls, {quditInfos.back()},
101	                               std::is_same_v<mod, adj>);
102	
103	  // If we did apply any X ops for a negative control, we need to reverse it.
104	  if (!controls.empty()) {
105	    for (std::size_t i = 0; i < controls.size(); i++) {
106	      if (qubitIsNegated[i]) {
107	        getExecutionManager()->apply("x", {}, {}, {controls[i]});
108	        // fold expression which will reverse the negation
109	        (
110	            [&] {
111	              if (args.is_negative())
112	                args.negate();
113	            }(),
114	            ...);
115	      }
116	    }
117	  }
118	}
119	
120	/// This function will apply a multi-controlled operation with the given control
121	/// register on the single qubit target.
122	template <typename QuantumOp, typename mod = ctrl, typename QubitRange>
123	  requires(std::ranges::range<QubitRange>)
124	void oneQubitApplyControlledRange(QubitRange &ctrls, qubit &target) {
125	  // Get the name of the operation
126	  auto gateName = QuantumOp::name();
127	
128	  // Map the input control register to a vector of QuditInfo
129	  std::vector<QuditInfo> controls;
130	  std::transform(ctrls.begin(), ctrls.end(), std::back_inserter(controls),
131	                 [](auto &q) { return cudaq::qubitToQuditInfo(q); });
132	
133	  // Apply the gate
134	  getExecutionManager()->apply(gateName, {}, controls,
135	                               {cudaq::qubitToQuditInfo(target)});
136	}
137	
138	#define CUDAQ_QIS_ONE_TARGET_QUBIT_(NAME)                                      \
139	  namespace types {                                                            \
140	  struct NAME {                                                                \
141	    static constexpr std::string_view name{#NAME};                             \
142	  };                                                                           \
143	  }                                                                            \
144	  template <typename mod = base, typename... QubitArgs>                        \
145	  void NAME(QubitArgs &...args) {                                              \
146	    oneQubitApply<qubit_op::NAME##Op, mod>(args...);                           \
147	  }                                                                            \
148	  template <typename mod = ctrl, typename QubitRange>                          \
149	    requires(std::ranges::range<QubitRange>)                                   \
150	  void NAME(QubitRange &ctrls, qubit &target) {                                \
151	    oneQubitApplyControlledRange<qubit_op::NAME##Op, mod>(ctrls, target);      \
152	  }                                                                            \
153	  template <typename mod = base, typename QubitRange>                          \
154	    requires(std::ranges::range<QubitRange>)                                   \
155	  void NAME(QubitRange &qr) {                                                  \
156	    for (auto &q : qr) {                                                       \
157	      NAME<mod>(q);                                                            \
158	    }                                                                          \
159	  }                                                                            \
160	  template <typename mod = base, typename QubitRange>                          \
161	    requires(std::ranges::range<QubitRange>)                                   \
162	  void NAME(QubitRange &&qr) {                                                 \
163	    for (auto &q : qr) {                                                       \
164	      NAME<mod>(q);                                                            \
165	    }                                                                          \
166	  }
167	
168	// Instantiate the above 3 functions for the default logical gate set
169	CUDAQ_QIS_ONE_TARGET_QUBIT_(h)
170	CUDAQ_QIS_ONE_TARGET_QUBIT_(x)
171	CUDAQ_QIS_ONE_TARGET_QUBIT_(y)
172	CUDAQ_QIS_ONE_TARGET_QUBIT_(z)
173	CUDAQ_QIS_ONE_TARGET_QUBIT_(t)
174	CUDAQ_QIS_ONE_TARGET_QUBIT_(s)
175	
176	template <typename QuantumOp, typename mod = base, typename ScalarAngle,
177	          typename... QubitArgs>
178	void oneQubitSingleParameterApply(ScalarAngle angle, QubitArgs &...args) {
179	  static_assert(std::conjunction<std::is_same<qubit, QubitArgs>...>::value,
180	                "Cannot operate on a qudit with Levels != 2");
181	  // Get the name of the operation
182	  auto gateName = QuantumOp::name();
183	
184	  // Map the qubits to their unique ids and pack them into a std::array
185	  constexpr std::size_t nArgs = sizeof...(QubitArgs);
186	  std::vector<QuditInfo> targets{qubitToQuditInfo(args)...};
187	  std::vector<double> parameters{static_cast<double>(angle)};
188	
189	  // If there are more than one qubits and mod == base, then
190	  // we just want to apply the same gate to all qubits provided
191	  if constexpr (nArgs > 1 && std::is_same_v<mod, base>) {
192	    for (auto &targetId : targets)
193	      getExecutionManager()->apply(gateName, parameters, {}, {targetId});
194	
195	    // Nothing left to do, return
196	    return;
197	  }
198	
199	  // If we are here, then mod must be control or adjoint
200	  // Extract the controls and the target
201	  std::vector<QuditInfo> controls(targets.begin(), targets.begin() + nArgs - 1);
202	
203	  // Apply the gate
204	  getExecutionManager()->apply(gateName, parameters, controls, {targets.back()},
205	                               std::is_same_v<mod, adj>);
206	}
207	
208	template <typename QuantumOp, typename mod = ctrl, typename ScalarAngle,
209	          typename QubitRange>
210	  requires(std::ranges::range<QubitRange>)
211	void oneQubitSingleParameterControlledRange(ScalarAngle angle,
212	                                            QubitRange &ctrls, qubit &target) {
213	  // Get the name of the operation
214	  auto gateName = QuantumOp::name();
215	
216	  // Map the input control register to a vector of QuditInfo
217	  std::vector<QuditInfo> controls;
218	  std::transform(ctrls.begin(), ctrls.end(), std::back_inserter(controls),
219	                 [](const auto &q) { return qubitToQuditInfo(q); });
220	
221	  // Apply the gate
222	  getExecutionManager()->apply(gateName, {angle}, controls,
223	                               {qubitToQuditInfo(target)});
224	}
225	
226	#define CUDAQ_QIS_PARAM_ONE_TARGET_(NAME)                                      \
227	  namespace types {                                                            \
228	  struct NAME {                                                                \
229	    static constexpr std::string_view name{#NAME};                             \
230	  };                                                                           \
