257	template <typename mod = base, typename ScalarAngle, typename... QubitArgs>
258	void u3(ScalarAngle theta, ScalarAngle phi, ScalarAngle lambda,
259	        QubitArgs &...args) {
260	  static_assert(std::conjunction<std::is_same<qubit, QubitArgs>...>::value,
261	                "Cannot operate on a qudit with Levels != 2");
262	
263	  std::vector<ScalarAngle> parameters{theta, phi, lambda};
264	
265	  // Map the qubits to their unique ids and pack them into a std::array
266	  constexpr std::size_t nArgs = sizeof...(QubitArgs);
267	  std::vector<QuditInfo> targets{qubitToQuditInfo(args)...};
268	
269	  // If there are more than one qubits and mod == base, then
270	  // we just want to apply the same gate to all qubits provided
271	  if constexpr (nArgs > 1 && std::is_same_v<mod, base>) {
272	    for (auto &targetId : targets)
273	      getExecutionManager()->apply("u3", parameters, {}, {targetId});
274	    return;
275	  }
276	
277	  // If we are here, then mod must be control or adjoint
278	  // Extract the controls and the target
279	  std::vector<QuditInfo> controls(targets.begin(), targets.begin() + nArgs - 1);
280	
281	  // Apply the gate
282	  getExecutionManager()->apply("u3", parameters, controls, {targets.back()},
283	                               std::is_same_v<mod, adj>);
284	}
285	template <typename mod = ctrl, typename ScalarAngle, typename QubitRange>
286	  requires(std::ranges::range<QubitRange>)
287	void u3(ScalarAngle theta, ScalarAngle phi, ScalarAngle lambda,
288	        QubitRange &ctrls, qubit &target) {
289	  std::vector<ScalarAngle> parameters{theta, phi, lambda};
290	  // Map the input control register to a vector of QuditInfo
291	  std::vector<QuditInfo> controls;
292	  std::transform(ctrls.begin(), ctrls.end(), std::back_inserter(controls),
293	                 [](const auto &q) { return qubitToQuditInfo(q); });
294	
295	  // Apply the gate
296	  getExecutionManager()->apply("u3", parameters, controls,
297	                               {qubitToQuditInfo(target)});
298	}
