307	template <typename mod = base, typename... QubitArgs>
308	void swap(QubitArgs &...args) {
309	  static_assert(std::conjunction<std::is_same<qubit, QubitArgs>...>::value,
310	                "Cannot operate on a qudit with Levels != 2");
311	  constexpr std::size_t nArgs = sizeof...(QubitArgs);
312	  std::vector<QuditInfo> qubitIds{qubitToQuditInfo(args)...};
313	  if constexpr (nArgs == 2) {
314	    getExecutionManager()->apply("swap", {}, {}, qubitIds);
315	    return;
316	  } else {
317	    static_assert(std::is_same_v<mod, ctrl>,
318	                  "More than 2 qubits passed to swap but modifier != ctrl.");
319	  }
320	
321	  // Controls are all qubits except the last 2
322	  std::vector<QuditInfo> controls(qubitIds.begin(),
323	                                  qubitIds.begin() + qubitIds.size() - 2);
324	  std::vector<QuditInfo> targets(qubitIds.end() - 2, qubitIds.end());
325	  getExecutionManager()->apply("swap", {}, controls, targets);
326	}
